head.script:
	const pathSegments = window.location.pathname.split('/').filter(segment => segment.length > 0);                                                                 
const folderName = pathSegments[0];
	if (folderName === 'global-wealth' || folderName === 'internationalbanking') {
      if (window.location.pathname !== '/global-wealth/index.html') {
        window.location.href = '/global-wealth/index.html';
       }
    } else {
    if (window.location.pathname !== '/default.page') {                                                                                                                   
      window.location.href = '/default.page';                                                                                                                     }
}
